#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX 500

int numberOfEnclaves(int** grid, int gridSize, int* gridColSize) {
    if (gridSize == 0 || gridColSize[0] == 0) return 0;

    int n = gridSize, m = gridColSize[0];
    bool** vis = (bool**)malloc(n * sizeof(bool*));
    for (int i = 0; i < n; i++) {
        vis[i] = (bool*)malloc(m * sizeof(bool));
        for (int j = 0; j < m; j++) vis[i][j] = false;
    }

    int delrow[] = {-1, 0, 1, 0};
    int delcol[] = {0, +1, 0, -1};

    // Traverse all boundary cells and enqueue boundary lands
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (i == 0 || j == 0 || i == n - 1 || j == m - 1) {
                if (grid[i][j] == 1) {
                    vis[i][j] = true;
                    // Perform BFS from this cell
                    int q[100000][2], front = 0, rear = 0;
                    q[rear][0] = i, q[rear++][1] = j;
                    while (front < rear) {
                        int row = q[front][0], col = q[front++];
                        for (int k = 0; k < 4; k++) {
                            int nrow = row + delrow[k], ncol = col + delcol[k];
                            if (nrow >= 0 && nrow < n && ncol >= 0 && ncol < m && !vis[nrow][ncol] && grid[nrow][ncol] == 1) {
                                vis[nrow][ncol] = true;
                                q[rear][0] = nrow, q[rear++][1] = ncol;
                            }
                        }
                    }
                }
            }
        }
    }

    // Count land cells that are not visited (i.e., enclaves)
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (grid[i][j] == 1 && !vis[i][j]) cnt++;
        }
    }
    return cnt;
}

